import React, { useState } from "react";
import { motion } from "framer-motion";
import Image from "next/image";
import {
  Clock,
  Loader2,
  MoreVertical,
  PanelLeftClose,
  PanelLeftOpen,
  Plus,
  Search,
  Trash2,
  User,
} from "lucide-react";
import type { Conversation } from "./chat-types";

function GlowingPlusIcon({ compact = false }: { compact?: boolean }) {
  if (compact) {
    return (
      <div
        className="relative flex h-11 w-11 items-center justify-center rounded-full"
        style={{
          boxShadow:
            "0 0 20px rgba(255,106,61,0.38), 0 0 38px rgba(255,45,85,0.22)",
        }}
      >
        <div className="absolute inset-0 rounded-full bg-gradient-to-br from-[#ff7a3d] via-[#ff533d] to-[#ff2d55]" />
        <div className="absolute inset-[1px] rounded-full bg-gradient-to-br from-white/18 to-white/6" />
        <Plus className="relative z-10 h-5 w-5 text-white" strokeWidth={2.6} />
      </div>
    );
  }

  return (
    <div
      className="relative flex h-9 w-9 items-center justify-center rounded-full"
      style={{
        boxShadow:
          "0 0 18px rgba(255,106,61,0.34), 0 0 34px rgba(255,45,85,0.22)",
      }}
    >
      <motion.div
        className="absolute inset-0 rounded-full"
        animate={{ rotate: [0, 360] }}
        transition={{
          duration: 6,
          repeat: Infinity,
          ease: "linear",
        }}
        style={{
          background:
            "conic-gradient(from 0deg, #ff7a3d 0deg, #ff533d 120deg, #ff2d55 240deg, #ff7a3d 360deg)",
        }}
      />
      <div className="absolute inset-[1px] rounded-full bg-gradient-to-br from-white/20 to-white/8" />
      <Plus className="relative z-10 h-4 w-4 text-white" strokeWidth={2.6} />
    </div>
  );
}

export default function ChatSidebar({
  isSidebarCollapsed,
  onToggleSidebar,
  onStartNewChat,
  conversationSearch,
  setConversationSearch,
  filteredConversations,
  selectedSessionId,
  onOpenSession,
  onDeleteSession,
  loadingSessions,
}: {
  isSidebarCollapsed: boolean;
  onToggleSidebar: () => void;
  onStartNewChat: () => void;
  conversationSearch: string;
  setConversationSearch: (value: string) => void;
  filteredConversations: Conversation[];
  selectedSessionId: string | null;
  onOpenSession: (sessionId: string) => void;
  onDeleteSession: (sessionId: string) => void;
  loadingSessions: boolean;
}) {
  const [menuForId, setMenuForId] = useState<string | null>(null);

  const openSidebarIfCollapsed = () => {
    if (isSidebarCollapsed) onToggleSidebar();
  };

  return (
    <motion.aside
      animate={{ width: isSidebarCollapsed ? 76 : 318 }}
      transition={{ type: "spring", stiffness: 260, damping: 30 }}
      className="relative flex h-full shrink-0 flex-col border-r border-white/8 bg-[#151515]"
    >
      <div className="flex items-center justify-between gap-2 px-3 py-3">
        <div className="flex items-center gap-2">
          {!isSidebarCollapsed && (
            <Image
              src="/icon.png"
              alt="Logo"
              width={24}
              height={24}
              className="rounded-md"
            />
          )}
          <motion.button
            whileTap={{ scale: 0.96 }}
            onClick={onToggleSidebar}
            className={`flex h-10 w-10 items-center justify-center rounded-2xl border border-white/8 bg-white/[0.03] text-white/72 transition-colors duration-200 hover:border-white/14 hover:bg-white/[0.06] hover:text-white ${
              isSidebarCollapsed ? "translate-x-[7px]" : ""
            }`}
            title={isSidebarCollapsed ? "Open sidebar" : "Collapse sidebar"}
            aria-label={isSidebarCollapsed ? "Open sidebar" : "Collapse sidebar"}
          >
            {isSidebarCollapsed ? (
              <PanelLeftOpen className="h-5 w-5" />
            ) : (
              <PanelLeftClose className="h-5 w-5" />
            )}
          </motion.button>
        </div>
        <div className="flex items-center gap-1">
          <motion.button
            whileTap={{ scale: 0.96 }}
            onClick={onStartNewChat}
            className={`flex h-10 w-10 items-center justify-center rounded-2xl border border-white/8 bg-white/[0.03] text-white/72 transition-colors duration-200 hover:border-white/14 hover:bg-white/[0.06] hover:text-white ${
              isSidebarCollapsed ? "translate-x-[7px]" : ""
            }`}
            title="New Chat"
            aria-label="New Chat"
          >
            {isSidebarCollapsed ? (
              <Plus className="h-5 w-5" />
            ) : (
              <GlowingPlusIcon />
            )}
          </motion.button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto px-3 py-2">
        <div className="relative mb-2">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-white/40" />
          <input
            type="text"
            placeholder="Search chats..."
            value={conversationSearch}
            onChange={(e) => setConversationSearch(e.target.value)}
            className="w-full rounded-xl border border-white/8 bg-white/[0.03] py-2 pl-9 pr-3 text-sm text-white placeholder-white/40 outline-none transition-colors duration-200 hover:border-white/14 hover:bg-white/[0.06] focus:border-white/20 focus:bg-white/[0.08]"
          />
        </div>

        {loadingSessions ? (
          <div className="flex items-center justify-center py-8">
            <Loader2 className="h-6 w-6 animate-spin text-white/40" />
          </div>
        ) : filteredConversations.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-8 text-center">
            <p className="text-sm text-white/40">No conversations found</p>
          </div>
        ) : (
          <div className="space-y-1">
            {filteredConversations.map((conv) => (
              <div key={conv.id} className="group relative">
                <button
                  onClick={() => onOpenSession(conv.id)}
                  className={`flex w-full items-center gap-3 rounded-xl px-3 py-2.5 text-left transition-colors duration-200 ${
                    selectedSessionId === conv.id
                      ? "bg-white/[0.08] text-white"
                      : "text-white/60 hover:bg-white/[0.04] hover:text-white/80"
                  }`}
                >
                  <Clock className="h-4 w-4 shrink-0 opacity-60" />
                  <div className="min-w-0 flex-1">
                    <p className="truncate text-sm font-medium">{conv.title}</p>
                    <p className="truncate text-xs text-white/40">{conv.preview}</p>
                  </div>
                  {conv.unread && (
                    <span className="shrink-0 rounded-full bg-[#ff8a3d] px-1.5 py-0.5 text-[10px] font-bold text-white">
                      {conv.unread}
                    </span>
                  )}
                </button>
                <div className="absolute right-2 top-1/2 -translate-y-1/2 opacity-0 transition-opacity duration-200 group-hover:opacity-100">
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      onDeleteSession(conv.id);
                    }}
                    className="rounded-lg p-1.5 text-white/40 hover:bg-white/10 hover:text-white/80"
                    title="Delete"
                    aria-label="Delete conversation"
                  >
                    <Trash2 className="h-4 w-4" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      <div className="border-t border-white/8 p-3">
        <button className="flex w-full items-center gap-3 rounded-xl px-3 py-2.5 text-left text-sm text-white/60 transition-colors duration-200 hover:bg-white/[0.04] hover:text-white/80">
          <User className="h-4 w-4" />
          {!isSidebarCollapsed && <span>Profile</span>}
        </button>
      </div>
    </motion.aside>
  );
}
